from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # helper to strip surrounding quotes
    def clean(val: str) -> str:
        return val.strip('\"')

    # group triples by subject to avoid repeating the subject many times
    grouped: dict[str, list[Triple]] = {}
    for t in triples:
        grouped.setdefault(t.subject, []).append(t)

    sentences: list[str] = []

    for subj, group in grouped.items():
        # collect objects per predicate
        pred_objs: dict[str, list[str]] = {}
        for t in group:
            pred_objs.setdefault(t.predicate, []).append(clean(t.object))

        clauses: list[str] = []

        # birth information (date > year > place)
        if "birthDate" in pred_objs:
            clauses.append(f"was born on {pred_objs['birthDate'][0]}")
        elif "birthYear" in pred_objs:
            clauses.append(f"was born in {pred_objs['birthYear'][0]}")
        if "birthPlace" in pred_objs:
            clauses.append(f"in {pred_objs['birthPlace'][0]}")

        # death information
        if "deathDate" in pred_objs:
            clauses.append(f"died on {pred_objs['deathDate'][0]}")
        if "deathPlace" in pred_objs:
            clauses.append(f"in {pred_objs['deathPlace'][0]}")

        # origin / nationality
        if "origin" in pred_objs:
            clauses.append(f"originates from {pred_objs['origin'][0]}")
        if "nationality" in pred_objs:
            clauses.append(f"is {pred_objs['nationality'][0].lower()}")

        # genre
        if "genre" in pred_objs:
            genre = pred_objs["genre"][0]
            clauses.append(f"falls in the genre of {genre} music")

        # instrument
        if "instrument" in pred_objs:
            instr = pred_objs["instrument"][0].replace("The ", "").replace("the ", "")
            clauses.append(f"plays the {instr}")

        # occupation / background
        if "occupation" in pred_objs:
            clauses.append(f"is a {pred_objs['occupation'][0].lower()}")
        elif "background" in pred_objs:
            clauses.append(f"is a {pred_objs['background'][0].lower()}")

        # associated bands / musical artists – combine multiple objects
        if "associatedBand/associatedMusicalArtist" in pred_objs:
            bands = pred_objs["associatedBand/associatedMusicalArtist"]
            # simple heuristic: if more than one, use “has played with both … and …”
            if len(bands) == 1:
                clauses.append(f"is associated with {bands[0]}")
            else:
                # join with commas and “and”
                band_list = ", ".join(bands[:-1]) + f", and {bands[-1]}"
                clauses.append(f"has played with {band_list}")

        # record label
        if "recordLabel" in pred_objs:
            clauses.append(f"is signed to {pred_objs['recordLabel'][0]}")

        # active years – combine start and end if both present
        if "activeYearsStartYear" in pred_objs and "activeYearsEndYear" in pred_objs:
            clauses.append(f"was active from {pred_objs['activeYearsStartYear'][0]} to {pred_objs['activeYearsEndYear'][0]}")
        elif "activeYearsStartYear" in pred_objs:
            clauses.append(f"started a career in {pred_objs['activeYearsStartYear'][0]}")
        elif "activeYearsEndYear" in pred_objs:
            clauses.append(f"ended a career in {pred_objs['activeYearsEndYear'][0]}")

        # other generic predicates
        for p, objs in pred_objs.items():
            if p in {
                "birthDate","birthYear","birthPlace","deathDate","deathPlace",
                "origin","nationality","genre","instrument","occupation",
                "background","associatedBand/associatedMusicalArtist",
                "recordLabel","activeYearsStartYear","activeYearsEndYear"
            }:
                continue
            for o in objs:
                clauses.append(f"{p} {o}")

        # Build the sentence for this subject
        if not clauses:
            continue
        # join clauses with commas, add “and” before last if more than one
        if len(clauses) == 1:
            sentence = f"{subj} {clauses[0]}."
        else:
            sentence = f"{subj} " + ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
        sentences.append(sentence)

    # Combine sentences for different subjects into one paragraph
    return " ".join(sentences)

# EVOLVE-BLOCK-END

